 1	import * as React from 'react';
 2	import {
 3	  Divider,
 4	  Dropdown,
 5	  DropdownItem,
 6	  DropdownList,
 7	  MenuToggle,
 8	  MenuToggleElement,
 9	  Title,
10	} from '@patternfly/react-core';
11	import { useTranslation } from 'react-i18next';
12	import { TaskKind } from '../../../types';
13	import TaskSidebarShortcuts from './TaskSidebarShortcuts';
14	import PipelineResourceRef from '../../triggers-details/PipelineResourceRef';
15	
16	import './TaskSidebarHeader.scss';
17	
18	type TaskSidebarHeaderProps = {
19	  removeThisTask: () => void;
20	  taskResource: TaskKind;
21	};
22	
23	const TaskSidebarHeader: React.FC<TaskSidebarHeaderProps> = ({
24	  removeThisTask,
25	  taskResource,
26	}) => {
27	  const { t } = useTranslation('plugin__pipelines-console-plugin');
28	
29	  const [isOpen, setIsOpen] = React.useState(false);
30	
31	  const onToggleClick = () => {
32	    setIsOpen(!isOpen);
33	  };
34	
35	  const onSelect = () => {
36	    setIsOpen(false);
37	  };
38	
39	  return (
40	    <div className="opp-task-sidebar-header">
41	      <Title headingLevel="h2" className="opp-task-sidebar-header__title">
42	        <div className="co-m-pane__name co-resource-item">
43	          <PipelineResourceRef
44	            resourceKind={taskResource.kind}
45	            resourceName={taskResource.metadata.name}
46	            largeIcon
47	            disableLink
48	          />
49	        </div>
50	        <div className="co-actions">
51	          <Dropdown
52	            isOpen={isOpen}
53	            onSelect={onSelect}
54	            onOpenChange={(isOpen: boolean) => setIsOpen(isOpen)}
55	            toggle={(toggleRef: React.Ref<MenuToggleElement>) => (
56	              <MenuToggle
57	                ref={toggleRef}
58	                onClick={onToggleClick}
59	                isExpanded={isOpen}
60	              >
61	                {t('Actions')}
62	              </MenuToggle>
63	            )}
64	          >
65	            <DropdownList>
66	              <DropdownItem key="remove-task" onClick={() => removeThisTask()}>
67	                {t('Remove task')}
68	              </DropdownItem>
69	            </DropdownList>
70	          </Dropdown>
71	        </div>
72	      </Title>
73	      <div className="opp-task-sidebar-header__shortcuts clearfix">
74	        <TaskSidebarShortcuts />
75	      </div>
76	      <Divider className="co-divider" />
77	    </div>
78	  );
79	};
80	
81	export default TaskSidebarHeader;

